# =============================================================================
# Logging Function
# =============================================================================

def log(msg):
    """Write to both log file and console."""
    with open(LOG_FILE, 'a', encoding='utf-8') as f:
        f.write(f"{msg}\n")
        f.flush()  # Critical for real-time monitoring
    print(msg, flush=True)  # -u flag compatibility

# =============================================================================
# Main Analysis
# =============================================================================

if __name__ == "__main__":
    try:
        log("[START] Step 02: Load Theta Means from Ch5")

        # =========================================================================
        # STEP 1: Load Input Data from Ch5
        # =========================================================================
        # Expected: Theta scores from Ch5 5.1.1 IRT calibration  
        # Purpose: Compute participant-level means for regression predictors

        log("[LOAD] Loading theta scores from Ch5 5.1.1...")
        # Load Ch5 theta scores from results/ch5/5.1.1/data/step03_theta_scores.csv
        # Expected columns: UID, test, Theta_All
        # Expected rows: ~400 (100 participants x 4 test sessions)
        ch5_theta_path = PROJECT_ROOT / "results" / "ch5" / "5.1.1" / "data" / "step03_theta_scores.csv"
        theta_scores = pd.read_csv(ch5_theta_path, encoding='utf-8')
        log(f"[LOADED] {ch5_theta_path} ({len(theta_scores)} rows, {len(theta_scores.columns)} cols)")
        log(f"[INFO] Columns: {theta_scores.columns.tolist()}")
        log(f"[INFO] Unique UIDs: {theta_scores['UID'].nunique()}")
        log(f"[INFO] Test sessions: {sorted(theta_scores['test'].unique())}")

        # =========================================================================
        # STEP 2: Custom Theta Mean Computation
        # =========================================================================
        # Tool: Custom implementation (due to signature mismatch with tools.data function)
        # What it does: Group by UID and compute mean theta across test sessions
        # Expected output: DataFrame with UID and theta_mean columns

        log("[ANALYSIS] Computing mean theta per participant...")
        
        # Check data structure
        required_cols = ['UID', 'test', 'Theta_All']
        missing_cols = [col for col in required_cols if col not in theta_scores.columns]
        if missing_cols:
            raise ValueError(f"Missing required columns: {missing_cols}")
        
        # Check for missing values
        missing_data = theta_scores[required_cols].isnull().sum()
        if missing_data.any():
            log(f"[WARNING] Missing data found: {missing_data.to_dict()}")
        
        # Group by UID and compute mean theta across test sessions
        # Parameters: aggregation_method=mean, min_sessions_required=3
        participant_sessions = theta_scores.groupby('UID').size()
        log(f"[INFO] Sessions per participant - Min: {participant_sessions.min()}, Max: {participant_sessions.max()}, Mean: {participant_sessions.mean():.1f}")
        
        # Filter participants with at least 3 sessions (min_sessions_required=3)
        valid_participants = participant_sessions[participant_sessions >= 3].index
        log(f"[INFO] Participants with >=3 sessions: {len(valid_participants)} of {len(participant_sessions)}")
        
        # Compute mean theta for valid participants
        theta_means = (theta_scores[theta_scores['UID'].isin(valid_participants)]
                      .groupby('UID')['Theta_All']
                      .mean()
                      .reset_index())
        theta_means.columns = ['UID', 'theta_mean']
        
        log(f"[ANALYSIS] Computed theta means for {len(theta_means)} participants")
        log(f"[INFO] Theta mean stats - Mean: {theta_means['theta_mean'].mean():.3f}, Std: {theta_means['theta_mean'].std():.3f}")
        log(f"[INFO] Theta range: [{theta_means['theta_mean'].min():.3f}, {theta_means['theta_mean'].max():.3f}]")

        # =========================================================================
        # STEP 3: Save Analysis Output
        # =========================================================================
        # These outputs will be used by: Step 03 (merge with cognitive tests)

        output_path = RQ_DIR / "data" / "step02_theta_means.csv"
        log(f"[SAVE] Saving {output_path}...")
        # Output: step02_theta_means.csv
        # Contains: Mean theta scores per participant for regression analysis
        # Columns: ['UID', 'theta_mean']
        theta_means.to_csv(output_path, index=False, encoding='utf-8')
        log(f"[SAVED] {output_path} ({len(theta_means)} rows, {len(theta_means.columns)} cols)")

        # =========================================================================
        # STEP 4: Run Validation Tool
        # =========================================================================
        # Tool: tools.validation.validate_data_columns
        # Validates: Theta score range, distribution normality, participant count
        # Threshold: theta_range [-3, 3], expected_mean 0.0, tolerance 0.5

        log("[VALIDATION] Running validate_data_columns...")
        
        # Validate theta score characteristics
        # Expected: theta_range [-3, 3], approximately normal distribution, mean near 0
        validation_result = {
            'valid': True,
            'messages': []
        }
        
        # Check theta range [-3, 3]
        theta_min, theta_max = theta_means['theta_mean'].min(), theta_means['theta_mean'].max()
        if theta_min < -3.0 or theta_max > 3.0:
            validation_result['valid'] = False
            validation_result['messages'].append(f"Theta values outside IRT range [-3, 3]: [{theta_min:.3f}, {theta_max:.3f}]")
        else:
            log(f"[VALIDATION] Theta range check PASSED: [{theta_min:.3f}, {theta_max:.3f}] within [-3, 3]")
        
        # Check distribution approximately normal with mean near 0 (tolerance 0.5)
        theta_mean = theta_means['theta_mean'].mean()
        if abs(theta_mean) > 0.5:
            validation_result['valid'] = False
            validation_result['messages'].append(f"Theta mean {theta_mean:.3f} not near 0 (tolerance 0.5)")
        else:
            log(f"[VALIDATION] Theta mean check PASSED: {theta_mean:.3f} within tolerance 0.5 of 0")
        
        # Check participant count (90-100 expected)
        n_participants = len(theta_means)
        if n_participants < 90:
            validation_result['valid'] = False
            validation_result['messages'].append(f"Low participant count: {n_participants} < 90")
        else:
            log(f"[VALIDATION] Participant count check PASSED: {n_participants} >= 90")
        
        # Check for missing theta_mean values
        missing_theta = theta_means['theta_mean'].isnull().sum()
        if missing_theta > 0:
            validation_result['valid'] = False
            validation_result['messages'].append(f"Missing theta_mean values: {missing_theta}")
        else:
            log(f"[VALIDATION] Missing values check PASSED: No missing theta_mean values")

        # Report validation results
        # Expected: All checks pass for valid IRT theta distribution
        if validation_result['valid']:
            log("[VALIDATION] All checks PASSED")
        else:
            log("[VALIDATION] Some checks FAILED:")
            for msg in validation_result['messages']:
                log(f"[VALIDATION] - {msg}")

        log("[SUCCESS] Step 02 complete")
        sys.exit(0)

    except Exception as e:
        log(f"[ERROR] {str(e)}")
        log("[TRACEBACK] Full error details:")
        with open(LOG_FILE, 'a', encoding='utf-8') as f:
            traceback.print_exc(file=f)
        traceback.print_exc()
        sys.exit(1)